def span_eligibility(span: str, contract: ResearchContract) -> list[str]:
    """IS THIS SPAN THE PAPER'S OWN, MEASURED FINDING? If not, it cannot carry an attributed claim.

    Two ways a perfectly verbatim span fails to be evidence FOR THE PAPER THAT CONTAINS IT:

      SECOND-HAND -- it reports somebody else's study. The finding, and the figure, belong to a paper we
        have not read and are not citing. Printing it under this paper's name is a fabricated binding.
      FORECAST    -- it projects rather than measures. There is no estimate, so there is nothing to
        adjudicate, and a projection placed in "conflict" with an estimate is a manufactured conflict.

    A card failing either test is still a real card; it simply may not serve as a TERM IN A COMPARISON
    or as an ATTRIBUTED evidence clause. We do not repair it and we do not silently drop it -- we record
    exactly why it is ineligible, and the planner prints the tally.
    """
    bad = []
    for pat in contract.secondhand_cues:
        m = re.search(pat, span, re.I)
        if m:
            bad.append(f'SECOND_HAND: the span reports another study ("{m.group(0)[:40]}") -- the '
                       f'finding is not this paper\'s own')
            break
    for pat in contract.forecast_cues:
        m = re.search(pat, span, re.I)
        if m:
            bad.append(f'FORECAST: the span projects rather than measures ("{m.group(0)[:30]}") -- a '
                       f'projection is not a finding and cannot be adjudicated')
            break
    return bad


